mapper.select:
SELECT lp.* FROM learning_progress lp
INNER JOIN chapters c ON lp.chapter_id = c.id
WHERE lp.user_id = #{userId} AND c.course_id = #{courseId}

mapper.update:
UPDATE learning_progress
last_position = #{lastPosition}, is_completed = #{isCompleted}, completed_at = #{completedAt}, last_watched_at = NOW(), total_watch_time = #{totalWatchTime}
WHERE id = #{id}

mapper.select:
SELECT COALESCE(SUM(lp.total_watch_time), 0) FROM learning_progress lp
INNER JOIN chapters c ON lp.chapter_id = c.id
WHERE lp.user_id = #{userId} AND c.course_id = #{courseId}
